-- Stock rolls and inward ledger movements.
WITH v AS (SELECT v.id AS variant_id FROM inv_variants v JOIN inv_products p ON p.id = v.product_id JOIN inv_categories c ON c.id = p.category_id WHERE c.normalized_name = 'vertical blind fabrics' AND p.normalized_name = 'vertical blind c-012' AND v.normalized_name = 'vertical blind c-012' LIMIT 1), ins AS (INSERT INTO inv_rolls (variant_id, batch_code, original_length, remaining_length, unit, purchase_rate, status, inward_date, bill_no, supplier, stock_value, notes) SELECT v.variant_id, 'VR-001', 60, 60, 'm', 565, 'in_stock', '2026-01-01', 'A2TR/25-26/3013', 'Vista Furnishing Limited', 33900, 'Import: Main Data for MTR Vertical' FROM v WHERE NOT EXISTS (SELECT 1 FROM inv_rolls r WHERE r.variant_id = v.variant_id AND r.batch_code = 'VR-001' AND r.notes = 'Import: Main Data for MTR Vertical') RETURNING id, variant_id) INSERT INTO inv_movements (roll_id, variant_id, movement_type, quantity, unit, rate, reference, note) SELECT ins.id, ins.variant_id, 'inflow', 60, 'm', 565, 'A2TR/25-26/3013', 'Initial vertical blind stock import' FROM ins;
